119: 
120:   // Throw counts are stored at the location of each throwing
121:   // instruction. This function looks for the previous throw count.
122:   //
123:   // Note: if the offset of the returned count is higher than the offset of
124:   // the immediate preceding PCCount, then this throw happened in the same
125:   // basic block.
126:   const PCCounts* getImmediatePrecedingThrowCounts(size_t offset) const;
127: 
128:   // Return the counter used to count the number of throws. Allocate it if
129:   // none exists yet. Returns null if the allocation failed.
