687:     const JS::ReadOnlyCompileOptions& options, JS::SourceText<Utf8Unit>& srcBuf,
688:     ScopeKind scopeKind) {
689:   return CompileGlobalScriptImpl(cx, fc, options, srcBuf, scopeKind,
